import type { CollectionEntry } from "astro:content";
import postFilter from "./postFilter";

/** Strip `zh` suffix from post id to get the base slug.
 *  Astro glob loader strips dots from filenames, so "foo.zh.md" becomes id "foozh". */
export function getBaseSlug(id: string, post?: CollectionEntry<"blog">): string {
  const parts = id.split("/");
  const last = parts[parts.length - 1];
  // Only strip zh suffix if the post is actually Chinese
  const isZh = post ? getPostLang(post) === "zh" : last.endsWith("zh");
  if (isZh) {
    parts[parts.length - 1] = last.replace(/zh$/, "");
  }
  return parts.join("/");
}

/** Get the language of a post from its frontmatter (defaults to "en") */
export function getPostLang(
  post: CollectionEntry<"blog">
): "en" | "zh" {
  return (post.data as any).lang === "zh" ? "zh" : "en";
}

/** Filter posts to a specific language */
export function getPostsForLang(
  posts: CollectionEntry<"blog">[],
  lang: "en" | "zh"
): CollectionEntry<"blog">[] {
  return posts.filter(post => getPostLang(post) === lang);
}

/** Build a map from base slug to { en, zh } post pairs */
export function buildTranslationMap(
  posts: CollectionEntry<"blog">[]
): Map<string, { en?: CollectionEntry<"blog">; zh?: CollectionEntry<"blog"> }> {
  const map = new Map<
    string,
    { en?: CollectionEntry<"blog">; zh?: CollectionEntry<"blog"> }
  >();

  for (const post of posts.filter(postFilter)) {
    const lang = getPostLang(post);
    const base = getBaseSlug(post.id, post);
    if (!map.has(base)) {
      map.set(base, {});
    }
    map.get(base)![lang] = post;
  }

  return map;
}

export const zh = {
  // Hero
  heroGreeting: "嗨，我是 Judy。",
  heroSubtitle: "ILLUCIO 联合创始人 & CTO",
  heroTagline: "凡是无法停歇的念头，我都将其构建为现实。",
  heroCta: "找我聊聊",

  // About
  aboutTitle: "关于我",
  aboutBio: `在技术与意义的交汇处，我致力于将那些挥之不去的灵感具象化。作为 ILLUCIO 的联合创始人兼 CTO，我正带领这款陪伴了 6,000+ 读者的 AI 阅读伙伴走向下一个形态。同时，我亦是互动叙事与实验性工具的构建者，在 AI 的人文边界持续探索，持续 Shipping。`,

  // Projects
  projectsTitle: "精选项目",
  projectsViewAll: "去 GitHub 看全部项目",

  // Contact
  contactTitle: "咖啡管够，来找我聊聊。",
  contactSubtitle: "当技术廉价如水，我们一起酿点不一样的。",

  // Nav
  navHome: "首页",
  navPosts: "博客",
  navProjects: "项目",
  navAbout: "关于",

  // Footer
  footerCopyright: "保留所有权利。",

  // About page
  aboutPageTitle: "关于我",
  aboutPageBio: `你好，我是陈小爷。我的构建动力源于对构想的执着。

我的作品涵盖了从追踪 760 万量级信息的技术关键词检索收集系统，到上线首日即获 5000 收藏的平行世界AI互动游戏；从探寻苏轼一生月相变化的人文动画，到反思反叛与归宿的悟空叙事。

作为 ILLUCIO 的联合创始人兼 CTO，我正为 6000 多名用户打造 AI 阅读伙伴。同时，我也在工业领域担任技术布道者，让复杂的 AI 在工业物联网（IIoT）中真正"落地"。我曾用两周自学摄影并在一个月内实现商业闭环——这种极速学习并交付价值的能力，贯穿我所有的项目。

我不界定"技术"与"创意"的边界。
当技术廉价如水一般廉价，唯有酿造者方能生存。`,
} as const;

export const en = {
  // Hero
