      </div>
    </section>
  </main>
  <Footer />
</Layout>

<script>
  function initAboutLang() {
    const lang = localStorage.getItem("lang") || "en";
    applyAboutLang(lang);
  }

  function applyAboutLang(lang: string) {
    const enBlock = document.getElementById("about-content-en");
    const zhBlock = document.getElementById("about-content-zh");
    if (enBlock && zhBlock) {
      enBlock.classList.toggle("hidden", lang === "zh");
      zhBlock.classList.toggle("hidden", lang !== "zh");
    }
    // Also handle the title
